import sys

class Solution:
    def findKthMissing(self, arr: list[int], k: int) -> int:
        # Ensure the array is sorted
        arr.sort()
        missing = 0
        prev = 0
        for num in arr:
            if num <= 0:
                continue
            # missing numbers between prev and current num
            gap = num - prev - 1
            if missing + gap >= k:
                return prev + k - missing
            missing += gap
            prev = num
        # If not found within the array, continue after the last element
        return prev + (k - missing)

