#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findKthMissing(vector<int>& arr, int k) {
        sort(arr.begin(), arr.end());
        long long missing = 0;
        int prev = 0;
        for (int num : arr) {
            if (num <= 0) continue;
            int gap = num - prev - 1;
            if (missing + gap >= k) {
                return prev + (k - missing);
            }
            missing += gap;
            prev = num;
        }
        return prev + (k - missing);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) cin >> arr[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.findKthMissing(arr, k);
    cout << ans << "\n";
    return 0;
}
